using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int Health = 100;
    public int MaxHealth = 100;
    public int Currency = 0;

    public void TakeDamage(int amount)
    {
        if (amount < 0) return;
        Health -= amount;
        if (Health < 0)
        {
            Health = 0;
        }
    }

    public void RestoreHealth(int amount)
    {
        if (amount < 0) return;
        Health += amount;
        if (Health > MaxHealth)
        {
            Health = MaxHealth;
        }
    }

    public void AddCurrency(int amount)
    {
        if (amount < 0) return;
        Currency += amount;
    }

    public bool TryPurchase(ShopItem item)
    {
        if (item == null)
        {
            return false;
        }

        if (Currency >= item.Price)
        {
            Currency -= item.Price;
            switch (item.Type)
            {
                case ItemType.HealthRestore:
                    RestoreHealth(item.Value);
                    break;
                case ItemType.DamageBoost:
                    // This would typically modify player's attack stat or give a temporary buff
                    // For this example, it's just a placeholder for an effect
                    break;
                case ItemType.CurrencyPack:
                    AddCurrency(item.Value);
                    break;
            }
            return true;
        }
        else
        {
            return false;
        }
    }
}

